109	  }
110	
111	  const responseTarget = await responseTargetForPost(post, slug);
112	
113	  const date = new Date(post.publishedAt!).toLocaleDateString("en-US", {
114	    year: "numeric",
115	    month: "long",
116	    day: "numeric",
