347	type PostResponseTargetInput = {
348	  id: string;
349	  organizationId: string;
350	  title: string;
351	  slug: string | null;
352	  publishedAt: Date | null;
353	};
354	
355	type PublishedConclusionDbRow = {
356	  id: string;
357	  kind: string;
358	  slug: string;
359	  version: number;
360	  sourceConclusionId: string;
361	  publishedAt: Date | string;
362	  doi: string;
363	  zenodoRecordId: string;
364	  discountedConfidence: number;
365	  statedConfidence: number;
366	  calibrationDiscountReason: string;
367	  payloadJson: string;
368	};
369	
370	async function responseTargetForPost(
371	  post: PostResponseTargetInput,
372	  routeSlug: string,
373	): Promise<PublishedConclusion> {
374	  const published = await db.publishedConclusion.findFirst({
375	    where: {
376	      organizationId: post.organizationId,
377	      OR: [
378	        { id: post.id },
379	        { sourceConclusionId: post.id },
380	        { sourceConclusionId: `article:${post.id}` },
381	        { slug: post.slug ?? routeSlug },
382	      ],
383	    },
384	    orderBy: { publishedAt: "desc" },
385	    select: {
386	      id: true,
387	      kind: true,
388	      slug: true,
389	      version: true,
390	      sourceConclusionId: true,
391	      publishedAt: true,
392	      doi: true,
393	      zenodoRecordId: true,
394	      discountedConfidence: true,
395	      statedConfidence: true,
396	      calibrationDiscountReason: true,
397	      payloadJson: true,
398	    },
399	  });
400	
401	  return published
402	    ? publishedConclusionFromRow(published as PublishedConclusionDbRow)
403	    : fallbackPostResponseTarget(post, routeSlug);
404	}
405	
406	function publishedConclusionFromRow(row: PublishedConclusionDbRow): PublishedConclusion {
407	  return {
408	    id: row.id,
409	    kind: row.kind,
410	    slug: row.slug,
411	    version: row.version,
412	    sourceConclusionId: row.sourceConclusionId,
413	    publishedAt:
414	      row.publishedAt instanceof Date
415	        ? row.publishedAt.toISOString()
416	        : new Date(row.publishedAt).toISOString(),
417	    doi: row.doi,
418	    zenodoRecordId: row.zenodoRecordId,
419	    discountedConfidence: row.discountedConfidence,
420	    statedConfidence: row.statedConfidence,
421	    calibrationDiscountReason: row.calibrationDiscountReason,
422	    payload: parsePublicationPayload(row),
423	  };
424	}
425	
426	function fallbackPostResponseTarget(
427	  post: PostResponseTargetInput,
428	  routeSlug: string,
429	): PublishedConclusion {
430	  const publishedAt = post.publishedAt
431	    ? post.publishedAt.toISOString()
432	    : new Date().toISOString();
433	  const slug = post.slug ?? routeSlug;
434	
435	  return {
436	    id: post.id,
437	    kind: "POST",
438	    slug,
439	    version: 1,
440	    sourceConclusionId: `post:${post.id}`,
441	    publishedAt,
442	    doi: "",
443	    zenodoRecordId: "",
444	    discountedConfidence: 0,
445	    statedConfidence: 0,
446	    calibrationDiscountReason: "",
447	    payload: {
448	      schema: "theseus.publicConclusion.v1",
449	      conclusionText: `Respond to this post: ${post.title}`,
450	      rationale: "",
451	      topicHint: "",
452	      evidenceSummary: "",
453	      exitConditions: [],
454	      strongestObjection: { objection: "", firmAnswer: "" },
455	      openQuestionsAdjacent: [],
456	      voiceComparisons: [],
457	      methodology: {
458	        schema: "theseus.methodology.v1",
459	        reviewerNarrative: "",
460	        profiles: [],
461	      },
462	      timeline: [],
463	      whatWouldChangeOurMind: [],
464	      citations: [],
465	    },
466	  };
467	}
468	
469	/**
470	 * Format a duration in seconds as `MM:SS` or `H:MM:SS` — what a podcast
471	 * app would show next to the play button.
472	 */
473	function formatDuration(seconds: number): string {
474	  const total = Math.max(0, Math.floor(seconds));
475	  const h = Math.floor(total / 3600);
476	  const m = Math.floor((total % 3600) / 60);
477	  const s = total % 60;
478	  const mm = m.toString().padStart(2, "0");
479	  const ss = s.toString().padStart(2, "0");
480	  return h > 0 ? `${h}:${mm}:${ss}` : `${m}:${ss}`;
481	}
482	
483	/**
484	 * Split prose into paragraphs. A "paragraph" is a block separated by
485	 * one-or-more blank lines. We also soft-split runs of plain single-line
486	 * content into paragraphs if they're long enough to warrant breaks —
487	 * but only when there are ZERO paragraph-break signals, so we don't
488	 * double-split well-formed text.
489	 */
490	function splitParagraphs(text: string): string[] {
491	  const trimmed = text.trim();
492	  if (!trimmed) return [];
493	  // Primary split: double-newline paragraph breaks (the normal case).
494	  const blocks = trimmed.split(/\n\s*\n+/);
495	  if (blocks.length > 1) {
496	    return blocks
497	      .map((b) => b.trim().replace(/\s+/g, " "))
498	      .filter(Boolean);
499	  }
500	  // Fallback: treat every 3–4 sentences as a paragraph so a long
501	  // one-line dump doesn't become an unreadable wall. 400 chars is a
502	  // reasonable paragraph in EB Garamond at 1.1rem.
503	  const SENT = /([^.!?]+[.!?]+)\s+(?=[A-Z])/g;
504	  const sentences = trimmed.replace(SENT, "$1\n").split(/\n/);
505	  const out: string[] = [];
506	  let buf = "";
507	  for (const s of sentences) {
508	    buf = buf ? buf + " " + s.trim() : s.trim();
509	    if (buf.length >= 400) {
510	      out.push(buf);
511	      buf = "";
512	    }
513	  }
514	  if (buf) out.push(buf);
515	  return out.length > 0 ? out : [trimmed];
516	}
