type PostResponseTargetInput = {
  id: string;
  organizationId: string;
  title: string;
  slug: string | null;
  publishedAt: Date | null;
};

type PublishedConclusionDbRow = {
  id: string;
  kind: string;
  slug: string;
  version: number;
  sourceConclusionId: string;
  publishedAt: Date | string;
  doi: string;
  zenodoRecordId: string;
  discountedConfidence: number;
  statedConfidence: number;
  calibrationDiscountReason: string;
  payloadJson: string;
};

async function responseTargetForPost(
  post: PostResponseTargetInput,
  routeSlug: string,
): Promise<PublishedConclusion> {
  const published = await db.publishedConclusion.findFirst({
    where: {
      organizationId: post.organizationId,
      OR: [
        { id: post.id },
        { sourceConclusionId: post.id },
        { sourceConclusionId: `article:${post.id}` },
        { slug: post.slug ?? routeSlug },
      ],
    },
    orderBy: { publishedAt: "desc" },
    select: {
      id: true,
      kind: true,
      slug: true,
      version: true,
      sourceConclusionId: true,
      publishedAt: true,
      doi: true,
      zenodoRecordId: true,
      discountedConfidence: true,
      statedConfidence: true,
      calibrationDiscountReason: true,
      payloadJson: true,
    },
  });

  return published
    ? publishedConclusionFromRow(published as PublishedConclusionDbRow)
    : fallbackPostResponseTarget(post, routeSlug);
}

function publishedConclusionFromRow(row: PublishedConclusionDbRow): PublishedConclusion {
  return {
    id: row.id,
    kind: row.kind,
    slug: row.slug,
    version: row.version,
    sourceConclusionId: row.sourceConclusionId,
    publishedAt:
      row.publishedAt instanceof Date
        ? row.publishedAt.toISOString()
        : new Date(row.publishedAt).toISOString(),
    doi: row.doi,
    zenodoRecordId: row.zenodoRecordId,
    discountedConfidence: row.discountedConfidence,
    statedConfidence: row.statedConfidence,
    calibrationDiscountReason: row.calibrationDiscountReason,
    payload: parsePublicationPayload(row),
  };
}

function fallbackPostResponseTarget(
  post: PostResponseTargetInput,
  routeSlug: string,
): PublishedConclusion {
  const publishedAt = post.publishedAt
    ? post.publishedAt.toISOString()
    : new Date().toISOString();
  const slug = post.slug ?? routeSlug;

  return {
    id: post.id,
    kind: "POST",
    slug,
    version: 1,
    sourceConclusionId: `post:${post.id}`,
    publishedAt,
    doi: "",
    zenodoRecordId: "",
    discountedConfidence: 0,
    statedConfidence: 0,
    calibrationDiscountReason: "",
    payload: {
      schema: "theseus.publicConclusion.v1",
      conclusionText: `Respond to this post: ${post.title}`,
      rationale: "",
      topicHint: "",
      evidenceSummary: "",
      exitConditions: [],
      strongestObjection: { objection: "", firmAnswer: "" },
      openQuestionsAdjacent: [],
      voiceComparisons: [],
      methodology: {
        schema: "theseus.methodology.v1",
        reviewerNarrative: "",
        profiles: [],
      },
      timeline: [],
      whatWouldChangeOurMind: [],
      citations: [],
    },
  };
}

/**
 * Format a duration in seconds as `MM:SS` or `H:MM:SS` — what a podcast
 * app would show next to the play button.
 */
function formatDuration(seconds: number): string {
  const total = Math.max(0, Math.floor(seconds));
  const h = Math.floor(total / 3600);
  const m = Math.floor((total % 3600) / 60);
  const s = total % 60;
  const mm = m.toString().padStart(2, "0");
  const ss = s.toString().padStart(2, "0");
  return h > 0 ? `${h}:${mm}:${ss}` : `${m}:${ss}`;
}

/**
 * Split prose into paragraphs. A "paragraph" is a block separated by
 * one-or-more blank lines. We also soft-split runs of plain single-line
 * content into paragraphs if they're long enough to warrant breaks —
 * but only when there are ZERO paragraph-break signals, so we don't
 * double-split well-formed text.
 */
function splitParagraphs(text: string): string[] {
  const trimmed = text.trim();
  if (!trimmed) return [];
  // Primary split: double-newline paragraph breaks (the normal case).
  const blocks = trimmed.split(/\n\s*\n+/);
  if (blocks.length > 1) {
    return blocks
      .map((b) => b.trim().replace(/\s+/g, " "))
      .filter(Boolean);
  }
  // Fallback: treat every 3–4 sentences as a paragraph so a long
  // one-line dump doesn't become an unreadable wall. 400 chars is a
  // reasonable paragraph in EB Garamond at 1.1rem.
  const SENT = /([^.!?]+[.!?]+)\s+(?=[A-Z])/g;
  const sentences = trimmed.replace(SENT, "$1\n").split(/\n/);
  const out: string[] = [];
  let buf = "";
  for (const s of sentences) {
    buf = buf ? buf + " " + s.trim() : s.trim();
    if (buf.length >= 400) {
      out.push(buf);
      buf = "";
    }
  }
  if (buf) out.push(buf);
  return out.length > 0 ? out : [trimmed];
}

