              className="mono"
              style={{
                color: "var(--amber-dim)",
                display: "inline-block",
                fontSize: "0.6rem",
                letterSpacing: "0.28em",
                marginBottom: "1.5rem",
                textDecoration: "none",
                textTransform: "uppercase",
              }}
            >
              &larr; Back to index
            </Link>
            <RespondCallout conclusions={[row]} />
          </>
        }
        bottomSlot={<ReaderResponses publishedConclusionId={row.id} />}
      />
    </div>
