  });

  it("renders print endnotes with stable numbering and no leaked private URLs", () => {
    const row = conclusion({
      payload: {
        ...conclusion().payload,
        article: {
          kind: "THEMATIC",
          bodyMarkdown: "## Heading\n\nBody.",
          sourceIds: [],
          citations: [
            {
              label: "S1",
              sourceKind: "opinion",
              sourceId: "op_1",
              quotedSpan: "evidence text",
